namespace Cysharp.Threading.Tasks.Internal
{
	internal sealed class ArrayPool<T>
	{
		private const int DefaultMaxNumberOfArraysPerBucket = 50;

		private static readonly T[] EmptyArray = new T[0];

		public static readonly ArrayPool<T> Shared = new ArrayPool<T>();

		private readonly MinimumQueue<T[]>[] buckets;

		private readonly SpinLock[] locks;

		private ArrayPool()
		{
			buckets = new MinimumQueue<T[]>[18];
			locks = new SpinLock[18];
			for (int i = 0; i < buckets.Length; i++)
			{
				buckets[i] = new MinimumQueue<T[]>(4);
				locks[i] = new SpinLock(enableThreadOwnerTracking: false);
			}
		}

		public T[] Rent(int minimumLength)
		{
			if (minimumLength < 0)
			{
				throw new ArgumentOutOfRangeException("minimumLength");
			}
			if (minimumLength == 0)
			{
				return EmptyArray;
			}
			int num = CalculateSize(minimumLength);
			int queueIndex = GetQueueIndex(num);
			if (queueIndex != -1)
			{
				MinimumQueue<T[]> minimumQueue = buckets[queueIndex];
				bool lockTaken = false;
				try
				{
					locks[queueIndex].Enter(ref lockTaken);
					if (minimumQueue.Count != 0)
					{
						return minimumQueue.Dequeue();
					}
				}
				finally
				{
					if (lockTaken)
					{
						locks[queueIndex].Exit(useMemoryBarrier: false);
					}
				}
			}
			return new T[num];
		}

		public void Return(T[] array, bool clearArray = false)
		{
			if (array == null || array.Length == 0)
			{
				return;
			}
			int queueIndex = GetQueueIndex(array.Length);
			if (queueIndex == -1)
			{
				return;
			}
			if (clearArray)
			{
				Array.Clear(array, 0, array.Length);
			}
			MinimumQueue<T[]> minimumQueue = buckets[queueIndex];
			bool lockTaken = false;
			try
			{
				locks[queueIndex].Enter(ref lockTaken);
				if (minimumQueue.Count <= 50)
				{
					minimumQueue.Enqueue(array);
				}
			}
			finally
			{
				if (lockTaken)
				{
					locks[queueIndex].Exit(useMemoryBarrier: false);
				}
			}
		}

		private static int CalculateSize(int size)
		{
			size--;
			size |= size >> 1;
			size |= size >> 2;
			size |= size >> 4;
			size |= size >> 8;
			size |= size >> 16;
			size++;
			if (size < 8)
			{
				size = 8;
			}
			return size;
		}

		private static int GetQueueIndex(int size)
		{
			return size switch
			{
				8 => 0, 
				16 => 1, 
				32 => 2, 
				64 => 3, 
				128 => 4, 
				256 => 5, 
				512 => 6, 
				1024 => 7, 
				2048 => 8, 
				4096 => 9, 
				8192 => 10, 
				16384 => 11, 
				32768 => 12, 
				65536 => 13, 
				131072 => 14, 
				262144 => 15, 
				524288 => 16, 
				1048576 => 17, 
				_ => -1, 
			};
		}
	}
	internal static class ArrayPoolUtil
	{
		public struct RentArray<T>(T[] array, int length, ArrayPool<T> pool) : IDisposable
		{
			public readonly T[] Array = array;

			public readonly int Length = length;

			private ArrayPool<T> pool = pool;

			public void Dispose()
			{
				DisposeManually(!RuntimeHelpersAbstraction.IsWellKnownNoReferenceContainsType<T>());
			}

			public void DisposeManually(bool clearArray)
			{
				if (pool != null)
				{
					if (clearArray)
					{
						System.Array.Clear(Array, 0, Length);
