	internal sealed class PooledDelegate<T> : ITaskPoolNode<PooledDelegate<T>>
	{
		private static TaskPool<PooledDelegate<T>> pool;

		private PooledDelegate<T> nextNode;

		private readonly Action<T> runDelegate;

		private Action continuation;

		public ref PooledDelegate<T> NextNode => ref nextNode;

		static PooledDelegate()
		{
			TaskPool.RegisterSizeGetter(typeof(PooledDelegate<T>), () => pool.Size);
		}

		private PooledDelegate()
		{
			runDelegate = Run;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static Action<T> Create(Action continuation)
		{
			if (!pool.TryPop(out var result))
			{
				result = new PooledDelegate<T>();
			}
			result.continuation = continuation;
			return result.runDelegate;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private void Run(T _)
		{
			Action action = continuation;
			continuation = null;
			if (action != null)
			{
				pool.TryPush(this);
				action();
			}
		}
	}
	internal static class RuntimeHelpersAbstraction
	{
		private static class WellKnownNoReferenceContainsType<T>
		{
			public static readonly bool IsWellKnownType;

			static WellKnownNoReferenceContainsType()
			{
				IsWellKnownType = WellKnownNoReferenceContainsTypeInitialize(typeof(T));
			}
		}

		public static bool IsWellKnownNoReferenceContainsType<T>()
		{
			return WellKnownNoReferenceContainsType<T>.IsWellKnownType;
		}

		private static bool WellKnownNoReferenceContainsTypeInitialize(Type t)
		{
			if (t.IsPrimitive)
			{
				return true;
			}
			if (t.IsEnum)
			{
				return true;
			}
			if (t == typeof(DateTime))
			{
				return true;
			}
			if (t == typeof(DateTimeOffset))
			{
				return true;
			}
			if (t == typeof(Guid))
			{
				return true;
			}
			if (t == typeof(decimal))
			{
				return true;
			}
			if (t.IsGenericType && t.GetGenericTypeDefinition() == typeof(Nullable<>))
			{
				return WellKnownNoReferenceContainsTypeInitialize(t.GetGenericArguments()[0]);
			}
			if (t == typeof(Vector2))
			{
				return true;
			}
			if (t == typeof(Vector3))
			{
				return true;
			}
			if (t == typeof(Vector4))
			{
				return true;
			}
			if (t == typeof(Color))
			{
				return true;
			}
			if (t == typeof(Rect))
			{
				return true;
			}
			if (t == typeof(Bounds))
			{
				return true;
			}
			if (t == typeof(Quaternion))
			{
				return true;
			}
			if (t == typeof(Vector2Int))
			{
				return true;
			}
			if (t == typeof(Vector3Int))
			{
				return true;
			}
			return false;
		}
	}
