			}
		}

		private sealed class RectIntEqualityComparer : IEqualityComparer<RectInt>
		{
			public bool Equals(RectInt self, RectInt other)
			{
				if (self.x.Equals(other.x) && self.width.Equals(other.width) && self.y.Equals(other.y))
				{
