	internal sealed class SingleAssignmentDisposable : IDisposable
	{
		private readonly object gate = new object();

		private IDisposable current;

		private bool disposed;

		public bool IsDisposed
		{
			get
			{
				lock (gate)
				{
					return disposed;
				}
			}
		}

		public IDisposable Disposable
		{
			get
			{
				return current;
			}
			set
			{
				IDisposable disposable = null;
				bool flag;
				lock (gate)
				{
					flag = disposed;
					disposable = current;
					if (!flag)
					{
						if (value == null)
						{
							return;
						}
						current = value;
					}
				}
				if (flag && value != null)
				{
					value.Dispose();
				}
				else if (disposable != null)
				{
					throw new InvalidOperationException("Disposable is already set");
				}
			}
		}

		public void Dispose()
		{
			IDisposable disposable = null;
			lock (gate)
			{
				if (!disposed)
				{
					disposed = true;
					disposable = current;
					current = null;
				}
			}
			disposable?.Dispose();
		}
	}
	internal sealed class AsyncSubject<T> : IObservable<T>, IObserver<T>
	{
		private class Subscription : IDisposable
		{
			private readonly object gate = new object();

			private AsyncSubject<T> parent;

			private IObserver<T> unsubscribeTarget;

			public Subscription(AsyncSubject<T> parent, IObserver<T> unsubscribeTarget)
			{
				this.parent = parent;
				this.unsubscribeTarget = unsubscribeTarget;
			}

			public void Dispose()
			{
				lock (gate)
				{
					if (parent == null)
					{
						return;
					}
					lock (parent.observerLock)
					{
						if (parent.outObserver is ListObserver<T> listObserver)
						{
							parent.outObserver = listObserver.Remove(unsubscribeTarget);
						}
						else
						{
							parent.outObserver = EmptyObserver<T>.Instance;
						}
						unsubscribeTarget = null;
						parent = null;
					}
				}
			}
		}

		private object observerLock = new object();

		private T lastValue;

		private bool hasValue;

		private bool isStopped;

		private bool isDisposed;

		private Exception lastError;

		private IObserver<T> outObserver = EmptyObserver<T>.Instance;

		public T Value
		{
			get
			{
				ThrowIfDisposed();
				if (!isStopped)
				{
					throw new InvalidOperationException("AsyncSubject is not completed yet");
				}
				if (lastError != null)
				{
					ExceptionDispatchInfo.Capture(lastError).Throw();
				}
				return lastValue;
			}
		}

		public bool HasObservers
		{
			get
			{
				if (!(outObserver is EmptyObserver<T>) && !isStopped)
				{
					return !isDisposed;
				}
				return false;
			}
		}

		public bool IsCompleted => isStopped;

		public void OnCompleted()
		{
			IObserver<T> observer;
			T value;
			bool flag;
			lock (observerLock)
			{
				ThrowIfDisposed();
				if (isStopped)
				{
					return;
				}
				observer = outObserver;
				outObserver = EmptyObserver<T>.Instance;
				isStopped = true;
				value = lastValue;
				flag = hasValue;
			}
			if (flag)
			{
				observer.OnNext(value);
				observer.OnCompleted();
			}
			else
			{
				observer.OnCompleted();
			}
		}

		public void OnError(Exception error)
		{
			if (error == null)
			{
				throw new ArgumentNullException("error");
			}
			IObserver<T> observer;
			lock (observerLock)
			{
				ThrowIfDisposed();
				if (isStopped)
				{
					return;
				}
				observer = outObserver;
				outObserver = EmptyObserver<T>.Instance;
				isStopped = true;
				lastError = error;
			}
			observer.OnError(error);
		}

		public void OnNext(T value)
		{
			lock (observerLock)
			{
				ThrowIfDisposed();
				if (!isStopped)
				{
					hasValue = true;
					lastValue = value;
				}
			}
		}

		public IDisposable Subscribe(IObserver<T> observer)
		{
			if (observer == null)
			{
				throw new ArgumentNullException("observer");
			}
			Exception ex = null;
			T value = default(T);
			bool flag = false;
			lock (observerLock)
			{
				ThrowIfDisposed();
				if (!isStopped)
				{
					if (outObserver is ListObserver<T> listObserver)
					{
						outObserver = listObserver.Add(observer);
					}
					else
					{
						IObserver<T> observer2 = outObserver;
						if (observer2 is EmptyObserver<T>)
						{
							outObserver = observer;
						}
						else
						{
							outObserver = new ListObserver<T>(new ImmutableList<IObserver<T>>(new IObserver<T>[2] { observer2, observer }));
						}
					}
					return new Subscription(this, observer);
				}
				ex = lastError;
				value = lastValue;
				flag = hasValue;
			}
			if (ex != null)
			{
				observer.OnError(ex);
			}
			else if (flag)
			{
				observer.OnNext(value);
				observer.OnCompleted();
			}
			else
			{
				observer.OnCompleted();
			}
			return EmptyDisposable.Instance;
		}

		public void Dispose()
		{
			lock (observerLock)
			{
				isDisposed = true;
				outObserver = DisposedObserver<T>.Instance;
				lastError = null;
				lastValue = default(T);
			}
		}

		private void ThrowIfDisposed()
		{
			if (isDisposed)
			{
				throw new ObjectDisposedException("");
			}
		}
	}
	internal class ListObserver<T> : IObserver<T>
	{
		private readonly ImmutableList<IObserver<T>> _observers;

		public ListObserver(ImmutableList<IObserver<T>> observers)
		{
			_observers = observers;
		}

		public void OnCompleted()
		{
			IObserver<T>[] data = _observers.Data;
			for (int i = 0; i < data.Length; i++)
			{
				data[i].OnCompleted();
			}
		}

		public void OnError(Exception error)
		{
			IObserver<T>[] data = _observers.Data;
			for (int i = 0; i < data.Length; i++)
			{
				data[i].OnError(error);
			}
		}

		public void OnNext(T value)
		{
			IObserver<T>[] data = _observers.Data;
			for (int i = 0; i < data.Length; i++)
			{
				data[i].OnNext(value);
			}
		}

		internal IObserver<T> Add(IObserver<T> observer)
		{
			return new ListObserver<T>(_observers.Add(observer));
		}

		internal IObserver<T> Remove(IObserver<T> observer)
		{
			int num = Array.IndexOf(_observers.Data, observer);
			if (num < 0)
			{
				return this;
			}
			if (_observers.Data.Length == 2)
			{
				return _observers.Data[1 - num];
			}
			return new ListObserver<T>(_observers.Remove(observer));
		}
	}
